FUNCTION CalculateLifecycleCO2(deviceSpec):
 manufacturingCO2 ← 0
 useCO2 ← 0
 disposalCO2 ← 0

 // Manufacturing: embedded carbon from each function chip
 FOR EACH function IN deviceSpec.functions:
 manufacturingCO2 ← manufacturingCO2 + function.embeddedCarbon

 // Use phase: active power + idle power over lifetime
 activeEnergy ← (deviceSpec.activeWatts * deviceSpec.activeHours * 365 * deviceSpec.lifetime)
 idleEnergy ← (deviceSpec.idleWatts * (24 - deviceSpec.activeHours) * 365 * deviceSpec.lifetime)
 totalEnergyKWh ← (activeEnergy + idleEnergy) / 1000
 useCO2 ← totalEnergyKWh * deviceSpec.gridEmissionFactor

 // Disposal: estimated based on total weight and recycling rate
 disposalCO2 ← deviceSpec.totalWeight * (1 - deviceSpec.recyclingRate) * 0.5

 RETURN {
 manufacturing: manufacturingCO2,
 use: useCO2,
 disposal: disposalCO2,
 total: manufacturingCO2 + useCO2 + disposalCO2
 }

// Example comparison
basicLaptop ← {
 functions: [
 {name: "CPU", embeddedCarbon: 200},
 {name: "Integrated Graphics", embeddedCarbon: 50}
 ],
 activeWatts: 25, idleWatts: 8, activeHours: 8,
 lifetime: 5, gridEmissionFactor: 0.5,
 totalWeight: 2000, recyclingRate: 0.3
}

gamingLaptop ← {
 functions: [
 {name: "CPU", embeddedCarbon: 200},
 {name: "Dedicated GPU", embeddedCarbon: 400},
 {name: "Audio Card", embeddedCarbon: 30}
 ],
 activeWatts: 80, idleWatts: 25, activeHours: 8,
 lifetime: 4, gridEmissionFactor: 0.5,
 totalWeight: 2500, recyclingRate: 0.3
}

result1 ← CalculateLifecycleCO2(basicLaptop)
result2 ← CalculateLifecycleCO2(gamingLaptop)
